from math import exp

parametros = {
    "w1": [0.404, 0.147, 0.363, 1.939],
    "w2": [0.348, 0.274, 0.306, 2.311],
    "b1": -0.544,
    "b2": -0.567,
    "v1": 2.051,
    "v2": 2.399,
    "c": -4.496,
}


def relu(z):
    return max(0.0, z)


def sigmoid(z):
    return 1.0 / (1.0 + exp(-z))


def prever_probabilidade(paciente, p):
    x = [
        paciente["idade"] / 100,
        paciente["pressao"] / 200,
        paciente["colesterol"] / 300,
        paciente["fumante"],
    ]
    z1 = sum(w * xi for w, xi in zip(p["w1"], x)) + p["b1"]
    z2 = sum(w * xi for w, xi in zip(p["w2"], x)) + p["b2"]
    h1 = relu(z1)
    h2 = relu(z2)
    return sigmoid(p["v1"] * h1 + p["v2"] * h2 + p["c"])


paciente = {"idade": 58, "pressao": 150, "colesterol": 245, "fumante": 1.0}
prob = prever_probabilidade(paciente, parametros)
classe = "sim" if prob >= 0.5 else "não"
print("Probabilidade:", round(prob, 4))
print("Classe prevista:", classe)

